class Solution {
    public int minimumOperationsToMakeEqual(int x, int y) {
        Queue<Integer> queue = new LinkedList<>();
        boolean[] visited = new boolean[20001];
        queue.offer(x);
        visited[x] = true;
        int steps = 0;
        while (!queue.isEmpty()) {
            int size = queue.size();
            for (int i = 0; i < size; i++) {
                int current = queue.poll();
                if (current == y) {
                    return steps;
                }
                if (current + 1 <= 10000 && !visited[current + 1]) {
                    queue.offer(current + 1);
                    visited[current + 1] = true;
                }
                if (current - 1 >= 1 && !visited[current - 1]) {
                    queue.offer(current - 1);
                    visited[current - 1] = true;
                }
                if (current % 11 == 0 && !visited[current / 11]) {
                    queue.offer(current / 11);
                    visited[current / 11] = true;
                }
                if (current % 5 == 0 && !visited[current / 5]) {
                    queue.offer(current / 5);
                    visited[current / 5] = true;
                }
            }
            steps++;
        }
        return -1;
    }
}
